// FindMonitor retrieves a single record by primary key
// If cols is empty Find will return all columns.
func FindMonitor(ctx context.Context, exec bob.Executor, IDPK string, cols ...string) (*Monitor, error) {
	if len(cols) == 0 {
		return Monitors.Query(
			sm.Where(Monitors.Columns.ID.EQ(sqlite.Arg(IDPK))),
		).One(ctx, exec)
	}

	return Monitors.Query(
		sm.Where(Monitors.Columns.ID.EQ(sqlite.Arg(IDPK))),
		sm.Columns(Monitors.Columns.Only(cols...)),
	).One(ctx, exec)
}

