// AfterQueryHook is called after Monitor is retrieved from the database
func (o *Monitor) AfterQueryHook(ctx context.Context, exec bob.Executor, queryType bob.QueryType) error {
	var err error

	switch queryType {
	case bob.QueryTypeSelect:
		ctx, err = Monitors.AfterSelectHooks.RunHooks(ctx, exec, MonitorSlice{o})
	case bob.QueryTypeInsert:
		ctx, err = Monitors.AfterInsertHooks.RunHooks(ctx, exec, MonitorSlice{o})
	case bob.QueryTypeUpdate:
		ctx, err = Monitors.AfterUpdateHooks.RunHooks(ctx, exec, MonitorSlice{o})
	case bob.QueryTypeDelete:
		ctx, err = Monitors.AfterDeleteHooks.RunHooks(ctx, exec, MonitorSlice{o})

	}

	return err
}

