// LoadHeartbeats loads the monitor's Heartbeats into the .R struct
func (o *Monitor) LoadHeartbeats(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Heartbeats = nil

	related, err := o.Heartbeats(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Monitor = o
	}

	o.R.Heartbeats = related
	return nil
}

// LoadHeartbeats loads the monitor's Heartbeats into the .R struct
func (os MonitorSlice) LoadHeartbeats(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	heartbeats, err := os.Heartbeats(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Heartbeats = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range heartbeats {

			if !(o.ID == rel.MonitorID) {
				continue
			}

			rel.R.Monitor = o

			o.R.Heartbeats = append(o.R.Heartbeats, rel)
		}
	}

	return nil
}

// LoadUser loads the monitor's User into the .R struct
func (o *Monitor) LoadUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.User = nil

	related, err := o.User(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.Monitors = MonitorSlice{o}

	o.R.User = related
	return nil
}

// LoadUser loads the monitor's User into the .R struct
func (os MonitorSlice) LoadUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	users, err := os.User(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range users {

			if !(o.UserID == rel.ID) {
				continue
			}

			rel.R.Monitors = append(rel.R.Monitors, o)

			o.R.User = rel
			break
		}
	}

	return nil
}

