// LoadCountHeartbeats loads the count of Heartbeats into the C struct
func (o *Monitor) LoadCountHeartbeats(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	count, err := o.Heartbeats(mods...).Count(ctx, exec)
	if err != nil {
		return err
	}

	o.C.Heartbeats = &count
	return nil
}

// LoadCountHeartbeats loads the count of Heartbeats for a slice in a single batch query
func (os MonitorSlice) LoadCountHeartbeats(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	// Build the IN arg expression from parent PKs
	PKArgSlice := make([]bob.Expression, 0, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}
		PKArgSlice = append(PKArgSlice, sqlite.Arg(o.ID))
	}
	PKArgExpr := sqlite.Group(PKArgSlice...)

	// countResult holds one scanned row from the batch count query.
	// FK columns are aliased to the parent PK column names for direct map lookup.
	type countResult struct {
		ID    string
		Count int64
	}

	batchMods := []bob.Mod[*dialect.SelectQuery]{
		// SELECT fk AS parent_pk, count(*)
		sm.Columns(
			Heartbeats.Columns.MonitorID.As("id"),
			sqlite.Raw("count(*) as count"),
		),
		// Single-hop: FROM related table directly
		sm.From(Heartbeats.NameAs()),

		// WHERE fk IN (parent PKs)
		sm.Where(Heartbeats.Columns.MonitorID.OP("IN", PKArgExpr)),
		// GROUP BY fk columns
		sm.GroupBy(Heartbeats.Columns.MonitorID),
	}
	batchMods = append(batchMods, mods...)

	results, err := bob.All(ctx, exec,
		sqlite.Select(batchMods...),
		scan.StructMapper[countResult](),
	)
	if err != nil {
		return err
	}

	// Single-column FK: direct map lookup
	countMap := make(map[string]int64, len(results))
	for _, r := range results {
		countMap[r.ID] = r.Count
	}
	for _, o := range os {
		if o == nil {
			continue
		}
		count := countMap[o.ID]
		o.C.Heartbeats = &count
	}

	return nil
}

